  1→package org.soetek.api;
  2→
  3→import java.util.Arrays;
  4→import java.util.Map;
  5→
  6→import org.apache.camel.CamelContext;
  7→import org.apache.camel.Exchange;
  8→import org.eclipse.microprofile.config.inject.ConfigProperty;
  9→import org.soetek.foundation.domain.UserSessionEntity;
 10→import org.soetek.foundation.exception.BusinessException;
 11→import org.soetek.foundation.exception.GenericExceptionMapper;
 12→import org.soetek.foundation.service.UserSessionService;
 13→import org.soetek.foundation.util.LogContext;
 14→import org.soetek.foundation.util.LogType;
 15→
 16→import cn.hutool.core.exceptions.ExceptionUtil;
 17→import cn.hutool.core.util.IdUtil;
 18→import cn.hutool.core.util.ObjectUtil;
 19→import cn.hutool.core.util.StrUtil;
 20→import io.quarkus.security.AuthenticationFailedException;
 21→import io.quarkus.security.credential.TokenCredential;
 22→import io.quarkus.security.identity.SecurityIdentity;
 23→import io.quarkus.security.runtime.QuarkusSecurityIdentity;
 24→import io.vertx.ext.web.RoutingContext;
 25→import jakarta.inject.Inject;
 26→import jakarta.inject.Named;
 27→import jakarta.ws.rs.Consumes;
 28→import jakarta.ws.rs.NotFoundException;
 29→import jakarta.ws.rs.POST;
 30→import jakarta.ws.rs.Path;
 31→import jakarta.ws.rs.PathParam;
 32→import jakarta.ws.rs.Produces;
 33→import jakarta.ws.rs.core.Context;
 34→import jakarta.ws.rs.core.MediaType;
 35→import jakarta.ws.rs.core.Response;
 36→import lombok.extern.slf4j.Slf4j;
 37→
 38→/**
 39→ * API 統一處理資源類別
 40→ *
 41→ * 提供統一的 REST API 入口點，動態路由到對應的 Apache Camel 處理器
 42→ * 支援 JWT 安全認證、請求追蹤、統一異常處理
 43→ *
 44→ * @author SoeTek Team
 45→ * @version 1.0
 46→ * @since 2026-01-07
 47→ */
 48→@Slf4j
 49→@Path("/api")
 50→public class HandlerApiResource {
 51→    /** Apache Camel 上下文，用於檢查路由是否存在 */
 52→    @Inject
 53→    CamelContext camelContext;
 54→
 55→    // 會話服務，用於驗證使用者會話
 56→    @Inject
 57→    @Named("userSessionService")
 58→    UserSessionService userSessionService;
 59→
 60→    // 允許匿名訪問的路徑，配置於 application.properties
 61→    @ConfigProperty(name = "quarkus.http.auth.permission.public.paths", defaultValue = "/api/auLogin,/api/auRegister")
 62→    String permitPublicPaths;
 63→
 64→    /**
 65→     * 統一 API 代理處理方法
 66→     *
 67→     * 動態路由 HTTP 請求到對應的 Apache Camel 路由進行業務處理
 68→     *
 69→     * @param ctx      HTTP 請求上下文
 70→     * @param route    路由名稱，對應 Apache Camel 的 direct 端點
 71→     * @param payload  請求的 JSON 資料
 72→     * @param identity 安全身份資訊，用於權限控制
 73→     * @return HTTP 回應，包含處理結果或錯誤資訊
 74→     */
 75→    @POST
 76→    @Path("/{route}")
 77→    @Consumes(MediaType.APPLICATION_JSON)
 78→    @Produces(MediaType.APPLICATION_JSON)
 79→    public Response handleProxy(@Context RoutingContext ctx,
 80→            @PathParam("route") String route,
 81→            Map<String, Object> payload,
 82→            @Context SecurityIdentity identity) {
 83→
 84→        // 設定日誌上下文 - API 請求開始
 85→        LogContext.setType(LogType.API_REQUEST);
 86→        LogContext.setComponent("HandlerApiResource");
 87→
 88→        String traceId = IdUtil.randomUUID();
 89→        long startTime = System.currentTimeMillis();
 90→        LogContext.setTraceId(traceId);
 91→
 92→        // 初始化 user 變數，對於包含用戶資訊的請求嘗試從 payload 獲取以改善日誌可讀性
 93→        String user = "anonymous";
 94→        if (payload != null) {
 95→            String payloadUser = null;
 96→            if ("auLogin".equals(route) && payload.containsKey("userAccount")) {
 97→                payloadUser = (String) payload.get("userAccount");
 98→                if (payloadUser != null && !payloadUser.trim().isEmpty()) {
 99→                    user = payloadUser + "(authenticating)";  // 標記為驗證中
100→                }
101→            } else if ("auRegister".equals(route) && payload.containsKey("userAccount")) {
102→                payloadUser = (String) payload.get("userAccount");
103→                if (payloadUser != null && !payloadUser.trim().isEmpty()) {
104→                    user = payloadUser + "(registering)";   // 標記為註冊中
105→                }
106→            } else if ("auChangePassword".equals(route) && payload.containsKey("userId")) {
107→                payloadUser = (String) payload.get("userId");
108→                if (payloadUser != null && !payloadUser.trim().isEmpty()) {
109→                    user = payloadUser + "(changing-pwd)";  // 標記為變更密碼中
110→                }
111→            }
112→        }
113→
114→        LogContext.setUser(user);
115→        log.info("API 請求開始 - Route: {}, TraceId: {}, User: {}", route, traceId, user);
116→
117→        try {
118→            String userAgent = StrUtil.nullToDefault(ctx.request().getHeader("User-Agent"), "");
119→            String sessionId = StrUtil.nullToDefault(ctx.request().getHeader("X-Session-Id"), "");
120→
121→            // XSS 檢查階段
122→            LogContext.setType(LogType.SEC_XSS);
123→            LogContext.setTraceId(traceId);
124→            log.debug("執行 XSS 安全檢查");
125→
126→            // 身份驗證階段
127→            LogContext.setType(LogType.API_AUTH);
128→            LogContext.setTraceId(traceId);
129→            log.debug("開始身份驗證流程");
130→            identity = validateSession(ctx.request().path(), identity,
131→                    ctx.request().getHeader("Authorization"), userAgent, sessionId);
132→
133→            // 設定使用者資訊 - 對於已認證用戶使用身份資訊，對於特殊路由保持 payload 用戶名稱
134→            if (identity != null && !identity.isAnonymous()) {
135→                user = identity.getPrincipal().getName();
136→            } else if (!("auLogin".equals(route) || "auRegister".equals(route) || "auChangePassword".equals(route))) {
137→                // 非特殊路由且未認證，重置為 anonymous
138→                user = "anonymous";
139→            }
140→            // 特殊路由（auLogin/auRegister/auChangePassword）保持原有的 payload 用戶名稱不變
141→
142→            LogContext.setUser(user);
143→
144→            // API 驗證階段
145→            LogContext.setType(LogType.API_VALIDATION);
146→            LogContext.setTraceId(traceId);
147→            LogContext.setUser(user);
148→            log.debug("開始 API 路由驗證");
149→
150→            // 判斷路由是否存在
151→            if (camelContext.hasEndpoint("direct:" + route) == null) {
152→                throw new NotFoundException(StrUtil.format("未知的 API 路徑 {}", ctx.request().path()));
153→            }
154→
155→            // 業務處理階段
156→            LogContext.setType(LogType.API_PROCESSING);
157→            LogContext.setTraceId(traceId);
158→            LogContext.setUser(user);
159→            log.debug("開始執行業務處理 - Route: {}", route);
160→
161→            // 執行路由
162→            Exchange exchange = camelContext.createFluentProducerTemplate()
163→                    .withHeaders(Map.of("X-Trace-Id", traceId,
164→                            "X-User", user,
165→                            "X-Session-Id", sessionId,
166→                            "User-Agent", userAgent))
167→                    .withExchangeProperty("payload", payload) // 備份 request payload 以利後續流程取得
168→                    .withExchangeProperty("startTime", startTime) // 記錄開始時間用於計算處理時間
169→                    .withBody(payload)
170→                    .to("direct:" + route)
171→                    .send();
172→
173→            // 回應處理階段 - 從 exchange header 重新獲取用戶資訊（業務處理器可能已更新）
174→            String exchangeUser = exchange.getIn().getHeader("X-User", String.class);
175→            if (exchangeUser != null && !exchangeUser.trim().isEmpty() && !"anonymous".equals(exchangeUser)) {
176→                user = exchangeUser;
177→                log.debug("從 Exchange Header 更新用戶資訊: {} -> {}",
178→                         LogContext.getUser(), user);
179→            }
180→
181→            LogContext.setType(LogType.API_RESPONSE);
182→            LogContext.setTraceId(traceId);
183→            LogContext.setUser(user);
184→            LogContext.setComponent("HandlerApiResource");
185→            log.debug("準備回應處理結果 - User: {}", user);
186→
187→            // 檢查並處理路由執行結果
188→            if (exchange.getException() != null) {
189→                throw exchange.getException();
190→            } else {
191→                // 直接返回 Processor 處理後的結果,不再額外包裝
192→                Object processorResult = exchange.getIn().getBody();
193→
194→                // 移除 entityId 欄位（僅用於 AuditLog，不對外回應）
195→                if (processorResult instanceof Map) {
196→                    @SuppressWarnings("unchecked")
197→                    Map<String, Object> resultMap = (Map<String, Object>) processorResult;
198→                    // 如果 Map 包含 entityId，創建可變副本並移除
199→                    if (resultMap.containsKey("entityId")) {
200→                        resultMap = new java.util.HashMap<>(resultMap);
201→                        resultMap.remove("entityId");
202→                        processorResult = resultMap;
203→                    }
204→                }
205→
206→                // 構建回應（包含 JSON 序列化）
207→                Response response = Response.ok(ObjectUtil.defaultIfNull(processorResult, Map.of())).build();
208→
209→                // 在回應構建後記錄完整處理時間（包含序列化時間）
210→                long processingTime = System.currentTimeMillis() - startTime;
211→                log.info("API 請求處理完成 - Route: {}, TraceId: {}, User: {}, ProcessingTime: {}ms",
212→                         route, traceId, user, processingTime);
213→
214→                return response;
215→            }
216→        } catch (BusinessException e) {
217→            // 業務邏輯錯誤 - 使用 BusinessException 的標準回應格式
218→            LogContext.setType(LogType.API_ERROR);
219→            LogContext.setTraceId(traceId);
220→            LogContext.setUser(user);
221→            LogContext.setComponent("HandlerApiResource");
222→            log.error("API 處理路由 {} 錯誤 - TraceId: {}, User: {}, Error: {}", route, traceId, user, e.getMessage());
223→
224→            // 構建符合標準回應格式
225→            Map<String, Object> response = new java.util.HashMap<>();
226→            response.put("success", false);
227→            response.put("code", e.getErrorCode());
228→            response.put("message", e.getErrorMessage());
229→            response.put("timestamp", java.time.Instant.now().toString());
230→            response.put("traceId", traceId);
231→
232→            // data 欄位：有額外資料時加入，否則設為 null
233→            response.put("data", e.hasData() ? e.getData() : null);
234→
235→            // meta 欄位：包含版本資訊
236→            response.put("meta", Map.of(
237→                    "version", "1.0",
238→                    "requestId", traceId
239→            ));
240→
241→            return Response.status(e.getHttpStatus())
242→                    .entity(response)
243→                    .build();
244→        } catch (Exception e) {
245→            // 系統錯誤或其他異常 - 使用通用錯誤格式
246→            LogContext.setType(LogType.API_ERROR);
247→            LogContext.setTraceId(traceId);
248→            LogContext.setUser(user);
249→            LogContext.setComponent("HandlerApiResource");
250→            log.error("API 處理路由 {} 錯誤 - TraceId: {}, User: {}, Error: {}", route, traceId, user, e.getMessage(), e);
251→
252→            // HandlerApiResource 層級的錯誤使用統一格式回應
253→            Response.Status status = GenericExceptionMapper.getResponseStatus(e);
254→            return Response.status(status)
255→                    .entity(Map.of(
256→                            "success", false,
257→                            "code", "ERROR",
258→                            "message", e.getMessage(),
259→                            "timestamp", java.time.Instant.now().toString(),
260→                            "traceId", traceId,
261→                            "data", Map.of("detail", ExceptionUtil.getRootCauseMessage(e)),
262→                            "meta", Map.of(
263→                                    "version", "1.0",
264→                                    "httpStatus", status.getStatusCode(),
265→                                    "httpStatusText", status.getReasonPhrase()
266→                            )
267→                    ))
268→                    .build();
269→        } finally {
270→            // 清理日誌上下文
271→            LogContext.clear();
272→        }
273→    }
274→
275→    /**
276→     * 驗證使用者會話
277→     *
278→     * 根據請求路徑、身份資訊、JWT token 和 User-Agent 驗證使用者會話的有效性
279→     *
280→     * @param path      請求路徑
281→     * @param identity  安全身份資訊
282→     * @param token     JWT token
283→     * @param userAgent 使用者代理字串
284→     * @param sessionId 使用者會話 ID
285→     * @return 驗證後的安全身份資訊，包含會話相關屬性
286→     * @throws AuthenticationFailedException 如果驗證失敗，拋出異常
287→     */
288→    private SecurityIdentity validateSession(String path, SecurityIdentity identity, String token, String userAgent,
289→            String sessionId) throws AuthenticationFailedException {
290→
291→        LogContext.setType(LogType.SEC_AUTH);
292→        log.debug("開始驗證用戶會話 - UserAgent: {}", userAgent);
293→
294→        // 公開路徑不需驗證 及 無身份資訊或匿名使用者亦不需驗證
295→        if (Arrays.asList(permitPublicPaths.trim().split("\\s*,\\s*")).contains(path) ||
296→                identity == null || identity.isAnonymous()) {
297→            return identity;
298→        }
299→        // 必須提供 token 和 user agent 和 session id
300→        if (StrUtil.isBlank(token) || StrUtil.isBlank(userAgent) || StrUtil.isBlank(sessionId)
301→                || !token.startsWith("Bearer ")) {
302→            throw new AuthenticationFailedException("缺少 JWT token 或 user agent 或 session id 或格式不正確");
303→        }
304→
305→        // 驗證會話（帶緩存）
306→        String tokenValue = token.substring(7).trim();
307→        String tokenHash = cn.hutool.crypto.digest.DigestUtil.sha256Hex(tokenValue);
308→
309→        // 使用 UserSessionService 的緩存方法驗證會話
310→        UserSessionEntity session = userSessionService.validateSessionWithCache(sessionId, tokenHash, userAgent);
311→
312→        // 如果會話無效
313→        if (session == null) {
314→            throw new AuthenticationFailedException("使用者會話錯誤或已過期，請重新登入");
315→        }
316→        return QuarkusSecurityIdentity.builder()
317→                .setPrincipal(identity.getPrincipal())
318→                .addRoles(identity.getRoles())
319→                .addCredential(identity.getCredential(TokenCredential.class))
320→                .addAttribute("sessionId", session.getSessionId())
321→                .addAttribute("deviceId", session.getDeviceId())
322→                .addAttribute("userAgent", session.getUserAgent())
323→                .build();
324→    }
325→}
