  1→package org.soetek.eap.demo.domain;
  2→
  3→import io.quarkus.hibernate.orm.panache.PanacheEntityBase;
  4→import io.quarkus.runtime.annotations.RegisterForReflection;
  5→import jakarta.persistence.Column;
  6→import jakarta.persistence.MappedSuperclass;
  7→import jakarta.persistence.PrePersist;
  8→import jakarta.persistence.PreUpdate;
  9→
 10→import java.time.LocalDateTime;
 11→
 12→import com.fasterxml.jackson.annotation.JsonFormat;
 13→import com.fasterxml.jackson.annotation.JsonIgnoreProperties;
 14→
 15→import io.quarkus.arc.Arc;
 16→import io.quarkus.security.identity.SecurityIdentity;
 17→
 18→/**
 19→ * EAP 資料庫審計基礎實體類別
 20→ *
 21→ * 為 EAP 資料庫中的實體提供審計功能，包括建立時間、建立者、更新時間、更新者
 22→ * 繼承此類的實體會自動記錄資料的建立和修改歷程
 23→ *
 24→ * 此類別與 org.soetek.foundation.domain.AuditableEntity 功能相同
 25→ * 但專用於 EAP 資料庫（eap 持久化單元），避免與 HRM 資料庫的基類衝突
 26→ *
 27→ * 設計原因：
 28→ * - Panache Entity 不能被多個持久化單元掃描
 29→ * - AuditableEntity 用於 HRM 資料庫（預設持久化單元）
 30→ * - AuditableEapEntity 用於 EAP 資料庫（eap 持久化單元）
 31→ * - 兩個基類分別在不同的 package，避免衝突
 32→ *
 33→ * @author SoeTek Team
 34→ * @version 1.0
 35→ * @since 2026-01-08
 36→ */
 37→@MappedSuperclass
 38→@RegisterForReflection
 39→@JsonIgnoreProperties(ignoreUnknown = true)
 40→public abstract class AuditableEapEntity extends PanacheEntityBase {
 41→
 42→    /**
 43→     * 建立者，記錄資料建立時的用戶
 44→     */
 45→    @Column(name = "CREATOR", nullable = false, length = 20, updatable = false)
 46→    public String creator;
 47→
 48→    /**
 49→     * 建立時間，記錄資料建立的時間戳記
 50→     */
 51→    @Column(name = "CREATE_DT", nullable = false, updatable = false)
 52→    @JsonFormat(pattern = "yyyy-MM-dd HH:mm:ss")
 53→    public LocalDateTime createDt;
 54→
 55→    /**
 56→     * 更新者，記錄最後修改資料的用戶
 57→     */
 58→    @Column(name = "UPDATER", nullable = false, length = 20)
 59→    public String updater;
 60→
 61→    /**
 62→     * 更新時間，記錄最後修改資料的時間戳記
 63→     */
 64→    @Column(name = "UPDATE_DT", nullable = false)
 65→    @JsonFormat(pattern = "yyyy-MM-dd HH:mm:ss")
 66→    public LocalDateTime updateDt;
 67→
 68→    /**
 69→     * 實體建立前的回調方法
 70→     *
 71→     * 在 JPA 持久化實體前自動設置建立時間和建立者資訊
 72→     * 簡化版本：使用 "system" 作為預設用戶
 73→     *
 74→     * TODO: 如需從安全上下文獲取用戶，可參考 AuditableEntity 的實現
 75→     */
 76→    @PrePersist
 77→    protected void onCreate() {
 78→        this.createDt = this.updateDt = LocalDateTime.now();
 79→        this.creator = this.updater = getCurrentUser();
 80→    }
 81→
 82→    /**
 83→     * 實體更新前的回調方法
 84→     *
 85→     * 在 JPA 更新實體前自動設置更新時間和更新者資訊
 86→     */
 87→    @PreUpdate
 88→    protected void onUpdate() {
 89→        this.updateDt = LocalDateTime.now();
 90→        this.updater = getCurrentUser();
 91→    }
 92→
 93→    /**
 94→     * 獲取當前操作用戶
 95→     *
 96→     * 從 Arc 容器取得 SecurityIdentity，回傳登入者帳號。
 97→     * 若無法取得（如系統排程、匿名），fallback 為 "system"。
 98→     *
 99→     * @return 當前用戶帳號或 "system"
100→     */
101→    protected String getCurrentUser() {
102→        try {
103→            SecurityIdentity identity = Arc.container()
104→                    .instance(SecurityIdentity.class).get();
105→            if (identity != null && !identity.isAnonymous()) {
106→                return identity.getPrincipal().getName();
107→            }
108→        } catch (Exception e) {
109→            // Arc 容器尚未初始化或無 SecurityIdentity
110→        }
111→        return "system";
112→    }
113→}
114→

  1→package org.soetek.eap.tm.processor;
  2→
  3→import io.quarkus.runtime.annotations.RegisterForReflection;
  4→import jakarta.enterprise.context.ApplicationScoped;
  5→import jakarta.enterprise.context.control.ActivateRequestContext;
  6→import jakarta.inject.Inject;
  7→import jakarta.inject.Named;
  8→import lombok.extern.slf4j.Slf4j;
  9→import org.apache.camel.Body;
 10→import org.apache.camel.Exchange;
 11→import org.apache.camel.Headers;
 12→import org.soetek.eap.tm.service.EmpVacationQueryService;
 13→import org.soetek.foundation.config.annotation.AuditLog;
 14→import org.soetek.foundation.processor.ApiRouteProcessor;
 15→import org.soetek.foundation.util.LogType;
 16→import org.soetek.foundation.util.PaginationUtil;
 17→import org.soetek.foundation.util.PaginationUtil.PaginationParams;
 18→import org.soetek.foundation.util.PaginationUtil.PaginationResult;
 19→
 20→import java.util.HashMap;
 21→import java.util.List;
 22→import java.util.Map;
 23→
 24→/**
 25→ * 員工年度假別額度清單查詢 Processor
 26→ * <p>
 27→ * 提供員工年度假別額度列表查詢功能，支援複合條件篩選與分頁。
 28→ * API 路徑：POST /api/empVacationQuery
 29→ * <p>
 30→ * 查詢條件（皆為選填）：
 31→ * - year:    年度（Integer，精準比對，前端預設帶入當前年度）
 32→ * - orgName: 部門名稱（String，模糊比對）
 33→ * - keyword: 員工編號或姓名（String，模糊比對）
 34→ * <p>
 35→ * 回應欄位（data.records 陣列，每筆）：
 36→ * - empId:      員工 ID（前端跳轉明細時使用）
 37→ * - empAccount: 員工編號
 38→ * - empName:    員工姓名
 39→ * - orgName:    部門名稱
 40→ *
 41→ * @author SoeTek Team
 42→ * @since 2026-03-18
 43→ */
 44→@Slf4j
 45→@ApplicationScoped
 46→@Named("empVacationQueryProcessor")
 47→@RegisterForReflection
 48→public class EmpVacationQueryProcessor extends ApiRouteProcessor {
 49→
 50→    @Inject
 51→    EmpVacationQueryService empVacationQueryService;
 52→
 53→    @Override
 54→    public Map<String, Object> getTemplateParams() {
 55→        return Map.of(
 56→                "routeId", "empVacationQuery",
 57→                "apiDescription", "查詢員工年度假別額度清單",
 58→                "requiredFields", ""
 59→        );
 60→    }
 61→
 62→    @Override
 63→    protected String getProcessorType() {
 64→        return LogType.API_PROCESSING;
 65→    }
 66→
 67→    @Override
 68→    @ActivateRequestContext
 69→    @AuditLog(
 70→            operation = AuditLog.OperationType.QUERY,
 71→            entity = "TmEmpVacation",
