  1→package org.soetek.eap.tm.service;
  2→
  3→import io.quarkus.hibernate.orm.PersistenceUnit;
  4→import jakarta.enterprise.context.ApplicationScoped;
  5→import jakarta.inject.Inject;
  6→import jakarta.persistence.EntityManager;
  7→import jakarta.persistence.Query;
  8→import lombok.extern.slf4j.Slf4j;
  9→import org.soetek.foundation.util.DateFormatUtil;
 10→
 11→import java.time.LocalDate;
 12→import java.time.LocalDateTime;
 13→import java.util.ArrayList;
 14→import java.util.HashMap;
 15→import java.util.LinkedHashMap;
 16→import java.util.List;
 17→import java.util.Map;
 18→
 19→/**
 20→ * 員工年度假別額度清單查詢服務
 21→ * <p>
 22→ * 以 TM_EMP_VACATION 為主表，JOIN 員工、組織、假別設定，
 23→ * 回傳每筆假別額度完整資料（一員工多假別 → 多列）。
 24→ * <p>
 25→ * 查詢條件：
 26→ * - year:     年度（精準比對 BEGIN_DATE 年份）
 27→ * - deptCode: 部門 ID（精準比對 PM_EMPLOYEE.ORG_ID）
 28→ * - empNo:    員工編號（模糊比對 EMP_ACCOUNT）
 29→ * - empName:  員工姓名（模糊比對 EMP_NAME）
 30→ * <p>
 31→ * 僅顯示在職員工（LEAVE_DATE IS NULL OR LEAVE_DATE >= GETDATE()）
 32→ *
 33→ * @author SoeTek Team
 34→ * @since 2026-03-18
 35→ */
 36→@Slf4j
 37→@ApplicationScoped
 38→public class EmpVacationQueryService {
 39→
 40→    @Inject
 41→    @PersistenceUnit("eap")
 42→    EntityManager em;
 43→
 44→    /**
 45→     * 查詢員工年度假別額度清單
 46→     *
 47→     * @param criteria 查詢條件 Map
 48→     * @return 每筆假別額度資料列表，欄位對應前端 EmployeeQuotaListItem
 49→     */
 50→    public List<Map<String, Object>> queryEmpVacationList(Map<String, Object> criteria) {
 51→
 52→        // Debug: 印出收到的所有參數
 53→        log.info("[員工假別清單] 收到的 criteria: {}", criteria);
 54→
 55→        String effectiveDate = extractString(criteria, "effectiveDate");
 56→        Integer deptCode     = extractInteger(criteria, "deptCode");
 57→        String empNo         = extractString(criteria, "empNo");
 58→        String empName       = extractString(criteria, "empName");
 59→        String sortBy        = extractString(criteria, "sortBy");
 60→        String sortOrder     = extractString(criteria, "sortOrder");
 61→
 62→        log.info("[員工假別清單] 解析後 - effectiveDate: '{}', deptCode: {}, empNo: '{}', empName: '{}'",
 63→                effectiveDate, deptCode, empNo, empName);
 64→
 65→        // 基底 SQL：以假別額度為單位（一員工可能有多筆假別）
 66→        StringBuilder sql = new StringBuilder("""
 67→                SELECT
 68→                    v.EMP_VACATION_ID       AS quotaId,
 69→                    v.EMP_ID                AS empId,
 70→                    YEAR(v.BEGIN_DATE)      AS year,
 71→                    e.EMP_ACCOUNT           AS empNo,
 72→                    e.EMP_NAME              AS empNameCh,
 73→                    e.EMP_NAME_EN           AS empNameEn,
 74→                    org.ORG_ID              AS deptCode,
 75→                    org.ORG_NAME            AS deptName,
 76→                    vds.VACATION_CODE       AS vacationCode,
 77→                    vs.VACATION_NAME        AS vacationName,
 78→                    vds.VACATION_SUB_CODE   AS vacationSubCode,
 79→                    vds.VACATION_SUB_NAME   AS vacationSubName,
 80→                    v.BEGIN_DATE            AS effectiveStartDate,
 81→                    v.END_DATE              AS effectiveEndDate,
 82→                    v.MAX_HOURS             AS totalHours,
 83→                    v.USED_HOURS            AS usedHours,
 84→                    v.UNUSED_HOURS          AS remainingHours,
 85→                    v.CLEAR                 AS settlementStatus,
 86→                    v.CASH_OUT_HOURS        AS cashOutHours
 87→                FROM EAP.TM_EMP_VACATION v
 88→                INNER JOIN EAP.PM_EMPLOYEE e
 89→                    ON e.EMP_ID = v.EMP_ID
 90→                LEFT JOIN EAP.AU_ORGANIZATION org
 91→                    ON org.ORG_ID = e.ORG_ID
 92→                INNER JOIN EAP.TM_VACATION_DETAIL_SETTING vds
 93→                    ON vds.VACATION_SUB_ID = v.VACATION_SUB_ID
 94→                INNER JOIN EAP.TM_VACATION_SETTING vs
 95→                    ON vs.VACATION_CODE = vds.VACATION_CODE
 96→                WHERE (e.LEAVE_DATE IS NULL OR e.LEAVE_DATE >= GETDATE())
 97→                """);
 98→
 99→        Map<String, Object> params = new LinkedHashMap<>();
100→
101→        // 生效/失效日期查詢（支援年份或完整日期）
102→        if (effectiveDate != null) {
103→            if (effectiveDate.matches("^\\d{4}$")) {
104→                // 純年份：篩選 BEGIN_DATE 年份等於輸入值
105→                sql.append("  AND YEAR(v.BEGIN_DATE) = :year\n");
106→                params.put("year", Integer.parseInt(effectiveDate));
107→            } else if (effectiveDate.matches("^\\d{4}-\\d{2}-\\d{2}$")) {
108→                // 完整日期：篩選該日期落在 BEGIN_DATE ~ END_DATE 區間內
109→                sql.append("  AND v.BEGIN_DATE <= :effectiveDate\n");
110→                sql.append("  AND v.END_DATE >= :effectiveDate\n");
111→                params.put("effectiveDate", LocalDate.parse(effectiveDate));
112→            }
113→        }
114→
115→        if (deptCode != null) {
116→            sql.append("  AND e.ORG_ID = :deptCode\n");
117→            params.put("deptCode", deptCode);
118→        }
119→
120→        if (empNo != null) {
121→            sql.append("  AND e.EMP_ACCOUNT LIKE :empNo\n");
122→            params.put("empNo", "%" + empNo + "%");
123→        }
124→
125→        if (empName != null) {
126→            sql.append("  AND e.EMP_NAME LIKE :empName\n");
127→            params.put("empName", "%" + empName + "%");
128→        }
129→
130→        sql.append(buildOrderBy(sortBy, sortOrder));
131→
132→        log.debug("[員工假別清單] 查詢條件 - effectiveDate:{}, deptCode:{}, empNo:{}, empName:{}",
133→                effectiveDate, deptCode, empNo, empName);
134→
135→        Query query = em.createNativeQuery(sql.toString());
136→        params.forEach(query::setParameter);
137→
138→        @SuppressWarnings("unchecked")
139→        List<Object[]> rows = query.getResultList();
140→
141→        List<Map<String, Object>> result = new ArrayList<>(rows.size());
142→        for (Object[] row : rows) {
143→            Map<String, Object> record = new HashMap<>();
144→            record.put("quotaId",            row[0]);
145→            record.put("empId",              row[1]);
146→            record.put("year",               row[2]);
147→            record.put("empNo",              row[3]);
148→            record.put("empNameCh",          row[4]);
149→            record.put("empNameEn",          row[5]);
150→            record.put("deptCode",           row[6]);
151→            record.put("deptName",           row[7]);
152→            record.put("vacationCode",       row[8]);
153→            record.put("vacationName",       row[9]);
154→            record.put("vacationSubCode",    row[10]);
155→            record.put("vacationSubName",    row[11]);
156→            record.put("effectiveStartDate", formatDate(row[12]));
157→            record.put("effectiveEndDate",   formatDate(row[13]));
158→            record.put("totalHours",         row[14]);
159→            record.put("usedHours",          row[15]);
160→            record.put("remainingHours",     row[16]);
161→            // 結算狀態：MSSQL BIT 欄位回傳為 Boolean 或 Integer
162→            Object clearVal = row[17];
163→            String settlementStatus = "";
164→            if (clearVal != null) {
165→                if (clearVal instanceof Boolean) {
166→                    settlementStatus = (Boolean) clearVal ? "Y" : "";
167→                } else if (clearVal instanceof Number) {
168→                    settlementStatus = ((Number) clearVal).intValue() == 1 ? "Y" : "";
169→                }
170→            }
171→            record.put("settlementStatus",   settlementStatus);
172→            record.put("cashOutHours",       row[18]);
173→            result.add(record);
174→        }
175→
176→        log.debug("[員工假別清單] 查詢完成，共 {} 筆", result.size());
177→        return result;
178→    }
179→
180→    // ==================== 私有輔助方法 ====================
181→
182→    /**
183→     * 依 sortBy 欄位名稱建立 ORDER BY 子句
184→     * 預設以員工編號 ASC 排序，次要排序為假別代碼 ASC
185→     */
186→    private String buildOrderBy(String sortBy, String sortOrder) {
187→        String direction = "desc".equalsIgnoreCase(sortOrder) ? "DESC" : "ASC";
188→        String column = switch (sortBy != null ? sortBy : "") {
189→            case "year"               -> "YEAR(v.BEGIN_DATE)";
190→            case "empNo"              -> "e.EMP_ACCOUNT";
191→            case "empNameCh"          -> "e.EMP_NAME";
192→            case "empNameEn"          -> "e.EMP_NAME_EN";
193→            case "vacationName"       -> "vs.VACATION_NAME";
194→            case "effectiveStartDate" -> "v.BEGIN_DATE";
195→            case "effectiveEndDate"   -> "v.END_DATE";
196→            case "totalHours"         -> "v.MAX_HOURS";
197→            case "usedHours"          -> "v.USED_HOURS";
198→            case "remainingHours"     -> "v.UNUSED_HOURS";
199→            default                  -> "e.EMP_ACCOUNT";
200→        };
201→        return "ORDER BY " + column + " " + direction + ", vds.VACATION_CODE ASC\n";
202→    }
203→
204→    /**
205→     * 將資料庫回傳的日期物件轉為 yyyy-MM-dd 字串
206→     * MSSQL DATE 型別透過 JDBC 可能回傳為 java.sql.Date, java.sql.Timestamp, 或 LocalDate
207→     */
208→    private String formatDate(Object dateObj) {
209→        if (dateObj == null) return null;
210→        if (dateObj instanceof java.sql.Date sqlDate) {
211→            return DateFormatUtil.formatDate(sqlDate.toLocalDate());
212→        }
213→        if (dateObj instanceof java.sql.Timestamp timestamp) {
214→            return DateFormatUtil.formatDate(timestamp.toLocalDateTime().toLocalDate());
215→        }
216→        if (dateObj instanceof LocalDateTime localDateTime) {
217→            return DateFormatUtil.formatDate(localDateTime.toLocalDate());
218→        }
219→        if (dateObj instanceof LocalDate localDate) {
220→            return DateFormatUtil.formatDate(localDate);
221→        }
222→        // 最後嘗試使用 toString，可能需要截取前 10 個字元 (yyyy-MM-dd)
223→        String str = dateObj.toString();
224→        if (str.length() >= 10) {
225→            return str.substring(0, 10);
226→        }
227→        return str;
228→    }
229→
230→    private Integer extractInteger(Map<String, Object> map, String key) {
231→        Object val = map.get(key);
232→        if (val == null) return null;
233→        if (val instanceof Number n) return n.intValue();
234→        String str = val.toString().trim();
235→        if (str.isEmpty()) return null;
236→        try {
237→            return Integer.parseInt(str);
238→        } catch (NumberFormatException e) {
239→            log.warn("[員工假別清單] 參數 '{}' 值 '{}' 無法解析為整數，已忽略", key, str);
240→            return null;
241→        }
242→    }
243→
244→    private String extractString(Map<String, Object> map, String key) {
245→        Object val = map.get(key);
246→        if (val == null) return null;
247→        String str = val.toString().trim();
248→        // 過濾空字串和字串 "null"
249→        if (str.isEmpty() || "null".equalsIgnoreCase(str)) {
250→            return null;
251→        }
252→        return str;
253→    }
254→}
