276→     * @return 符合條件的員工列表
277→     */
278→    public static List<PmEmployeeEntity> findAllEmployees(Map<String, Object> criteria) {
279→        StringBuilder query = new StringBuilder("FROM PmEmployeeEntity e WHERE 1=1");
280→        List<Object> params = new ArrayList<>();
281→
282→        // 公司代碼篩選
283→        if (criteria.containsKey("companyCode") && criteria.get("companyCode") != null) {
284→            String companyCode = criteria.get("companyCode").toString().trim();
285→            if (!companyCode.isEmpty()) {
286→                query.append(" AND e.companyCode = ?").append(params.size() + 1);
287→                params.add(companyCode);
288→            }
289→        }
290→
291→        // 部門篩選
292→        if (criteria.containsKey("orgId") && criteria.get("orgId") != null) {
293→            String orgId = criteria.get("orgId").toString().trim();
294→            if (!orgId.isEmpty()) {
295→                query.append(" AND e.orgId = ?").append(params.size() + 1);
296→                params.add(Integer.parseInt(orgId));
297→            }
298→        }
299→
300→        // 關鍵字搜尋（工號、中文姓名、英文姓名）
301→        if (criteria.containsKey("keyword") && criteria.get("keyword") != null) {
302→            String keyword = criteria.get("keyword").toString().trim();
303→            if (!keyword.isEmpty()) {
304→                query.append(" AND (e.empAccount LIKE ?").append(params.size() + 1);
305→                query.append(" OR e.empName LIKE ?").append(params.size() + 2);
306→                query.append(" OR e.empNameEn LIKE ?").append(params.size() + 3);
307→                query.append(")");
308→                String like = "%" + keyword + "%";
309→                params.add(like);
310→                params.add(like);
311→                params.add(like);
312→            }
313→        }
314→
315→        // 排序
316→        query.append(" ORDER BY e.empAccount");
317→
318→        PanacheQuery<PmEmployeeEntity> panacheQuery = find(query.toString(), params.toArray());
319→        return panacheQuery.list();
320→    }
