 27→/**
 28→ * 假別維護刪除 Processor
 29→ * <p>
 30→ * 提供假別明細刪除功能（物理刪除）
 31→ * API 路徑：/api/vacationDelete
 32→ * <p>
 33→ * 刪除邏輯：
 34→ * 1. 驗證 vacationSubId 必填
 35→ * 2. 查詢該明細記錄，取得 vacationCode
 36→ * 3. 判斷是否為特休假（vacationName = '特休假'）
 37→ *    - 如果是特休假，刪除關聯的特休設定（TM_VACATION_SPECIAL_SETTING）
 38→ * 4. 刪除該筆明細記錄
 39→ * 5. 檢查該假別是否還有其他明細
 40→ *    - 如果沒有其他明細，刪除主檔（TM_VACATION_SETTING）
 41→ *
 42→ * @author SoeTek Team
 43→ * @since 2026-03-13
 44→ */
 45→@Slf4j
 46→@ApplicationScoped
 47→@Named("vacationDeleteProcessor")
 48→@RegisterForReflection
 49→public class VacationDeleteProcessor extends ApiRouteProcessor {
 50→
 51→    /**
 52→     * EAP Schema 的 EntityManager（命名持久化單元 "eap"）
 53→     */
 54→    @Inject
 55→    @PersistenceUnit("eap")
 56→    EntityManager eapEntityManager;
 57→
 58→    /**
 59→     * 特休假名稱常數
 60→     */
 61→    private static final String SPECIAL_VACATION_NAME = "特休假";
 62→
 63→    /**
 64→     * 取得路由模板參數
 65→     *
 66→     * @return 路由參數 Map
 67→     */
 68→    @Override
 69→    public Map<String, Object> getTemplateParams() {
 70→        return Map.of(
 71→                "routeId", "vacationDelete",
 72→                "apiDescription", "刪除假別明細設定",
 73→                "requiredFields", "vacationSubId"
 74→        );
 75→    }
 76→
 77→    /**
 78→     * 取得處理器類型
 79→     *
 80→     * @return 處理器類型
 81→     */
 82→    @Override
 83→    protected String getProcessorType() {
 84→        return LogType.API_PROCESSING;
 85→    }
 86→
 87→    /**
 88→     * 處理假別明細刪除請求
 89→     *
 90→     * @param exchange Camel Exchange 物件
 91→     * @param payload  請求的 JSON 資料
 92→     * @param headers  請求標頭資訊
 93→     * @return 處理結果
 94→     * @throws Exception 處理過程中的異常
 95→     */
 96→    @Override
 97→    @ActivateRequestContext
 98→    @Transactional
 99→    @AuditLog(
100→            operation = AuditLog.OperationType.DELETE,
101→            entity = "TmVacationDetailSetting",
102→            description = "刪除假別明細設定",
103→            logParameters = true,
104→            logResult = true
105→    )
106→    public Object process(Exchange exchange, @Body Map<String, Object> payload,
107→                          @Headers Map<String, Object> headers) throws Exception {
108→        return executeWithErrorHandling(exchange, payload, headers);
109→    }
110→
111→    /**
112→     * 處理假別明細刪除業務邏輯
113→     *
114→     * @param exchange Camel Exchange 物件
115→     * @param payload  請求的 JSON 資料
116→     * @param headers  請求標頭資訊
117→     * @param traceId  追蹤 ID
118→     * @param routeId  路由 ID
119→     * @return 標準回應格式的 Map
120→     * @throws Exception 處理過程中的異常
121→     */
122→    @Override
123→    protected Object processBusinessLogic(
124→            Exchange exchange,
125→            Map<String, Object> payload,
126→            Map<String, Object> headers,
127→            String traceId,
128→            String routeId) throws Exception {
129→
130→        log.info("[假別刪除] 開始刪除假別明細 - TraceId: {}", traceId);
131→
132→        // ===== 1. 驗證 vacationSubId 必填 =====
133→        Integer vacationSubId = getRequiredInteger(payload, "vacationSubId", "明細流水號");
134→        log.debug("[假別刪除] 刪除目標 vacationSubId: {} - TraceId: {}", vacationSubId, traceId);
135→
136→        // ===== 2. 查詢該明細記錄 =====
137→        TmVacationDetailSettingEntity detailEntity = TmVacationDetailSettingEntity.findByKey(vacationSubId);
138→        if (detailEntity == null) {
139→            log.warn("[假別刪除] 明細記錄不存在 - vacationSubId: {}, TraceId: {}", vacationSubId, traceId);
140→            throw new BusinessException("DETAIL_NOT_FOUND", 404, "明細記錄不存在：" + vacationSubId);
141→        }
142→
143→        String vacationCode = detailEntity.vacationCode;
144→        String vacationSubCode = detailEntity.vacationSubCode;
145→        String vacationSubName = detailEntity.vacationSubName;
146→
147→        // ===== 3. 查詢主檔以判斷是否為特休假 =====
148→        TmVacationSettingEntity mainEntity = TmVacationSettingEntity.findByCode(vacationCode);
149→        if (mainEntity == null) {
150→            log.warn("[假別刪除] 主檔不存在 - vacationCode: {}, TraceId: {}", vacationCode, traceId);
151→            throw new BusinessException("VACATION_NOT_FOUND", 404, "假別主檔不存在：" + vacationCode);
152→        }
153→
154→        String vacationName = mainEntity.vacationName;
155→        boolean isSpecialVacation = SPECIAL_VACATION_NAME.equals(vacationName);
156→
157→        // ===== 4. 如果是特休假，刪除關聯的特休設定 =====
158→        long deletedSpecialCount = 0;
159→        if (isSpecialVacation) {
160→            deletedSpecialCount = TmSpecialVacationSettingEntity.deleteByVacationCode(vacationCode);
161→            log.debug("[假別刪除] 已刪除特休假設定 {} 筆 - vacationCode: {}, TraceId: {}",
162→                    deletedSpecialCount, vacationCode, traceId);
163→        }
164→
165→        // ===== 5. 刪除該筆明細記錄 =====
166→        detailEntity.delete();
167→        eapEntityManager.flush();
168→        log.debug("[假別刪除] 已刪除明細記錄 - vacationSubId: {}, TraceId: {}", vacationSubId, traceId);
169→
170→        // ===== 6. 檢查該假別是否還有其他明細 =====
171→        boolean mainDeleted = false;
172→        List<TmVacationDetailSettingEntity> remainingDetails = TmVacationDetailSettingEntity.findByCode(vacationCode);
173→
174→        if (remainingDetails.isEmpty()) {
175→            // 沒有其他明細，刪除主檔
176→            mainEntity.delete();
177→            eapEntityManager.flush();
178→            mainDeleted = true;
179→            log.info("[假別刪除] 已刪除最後一筆明細，連同主檔一起刪除 - vacationCode: {}, TraceId: {}",
180→                    vacationCode, traceId);
181→        }
182→
183→        log.info("[假別刪除] 刪除完成 - vacationSubId: {}, vacationCode: {}, vacationName: {}, " +
184→                        "isSpecialVacation: {}, deletedSpecialCount: {}, mainDeleted: {}, TraceId: {}",
185→                vacationSubId, vacationCode, vacationName, isSpecialVacation, deletedSpecialCount, mainDeleted, traceId);
186→
187→        // ===== 7. 組裝回應資料 =====
188→        Map<String, Object> data = new HashMap<>();
189→        data.put("vacationSubId", vacationSubId);
190→        data.put("vacationCode", vacationCode);
191→        data.put("vacationSubCode", vacationSubCode);
192→        data.put("vacationSubName", vacationSubName);
193→        data.put("vacationName", vacationName);
194→        data.put("isSpecialVacation", isSpecialVacation);
195→        data.put("deletedSpecialCount", deletedSpecialCount);
196→        data.put("mainDeleted", mainDeleted);
197→
198→        Map<String, Object> response = new HashMap<>();
199→        response.put("success", true);
200→        response.put("message", mainDeleted ? "刪除成功（已刪除最後一筆明細及主檔）" : "刪除成功");
201→        response.put("data", data);
202→        response.put("traceId", traceId);
203→
204→        return response;
205→    }
206→
207→    // ==================== 工具方法 ====================
208→
209→    /**
210→     * 取得必填整數
211→     *
212→     * @param data      資料 Map
213→     * @param key       欄位 key
214→     * @param fieldName 欄位顯示名稱（用於錯誤訊息）
215→     * @return 欄位值
216→     * @throws BusinessException 當欄位為空或無法轉換為整數時
217→     */
218→    private Integer getRequiredInteger(Map<String, Object> data, String key, String fieldName) {
219→        Object value = data.get(key);
220→        if (value == null) {
221→            throw new BusinessException("REQUIRED_FIELD", 400, fieldName + " 為必填欄位");
222→        }
223→        if (value instanceof Number) {
224→            return ((Number) value).intValue();
225→        }
226→        try {
227→            return Integer.parseInt(value.toString().trim());
228→        } catch (NumberFormatException e) {
229→            throw new BusinessException("INVALID_FORMAT", 400, fieldName + " 格式錯誤，必須為整數");
230→        }
231→    }
232→}
