 99→
100→    // ==================== Panache 查詢方法 ====================
101→
102→    /**
103→     * 查詢員工請假單列表（支援複合條件篩選）
104→     * <p>
105→     * 支援的查詢條件：
106→     * - empVacationId: 員工年度假別額度檔ID
107→     * - empAgentId: 代理員工ID
108→     * - leaveStatus: 簽核狀態
109→     * - beginTimeFrom: 起始時間（起）
110→     * - beginTimeTo: 起始時間（迄）
111→     * - sortBy: 排序欄位
112→     * - sortOrder: 排序方向 (asc/desc)
113→     *
114→     * @param criteria 查詢條件 Map
115→     * @return 符合條件的請假單列表
116→     */
117→    public static List<TmEmpLeaveEntity> findByCriteria(Map<String, Object> criteria) {
118→        StringBuilder query = new StringBuilder("FROM TmEmpLeaveEntity l WHERE 1=1");
119→        List<Object> params = new ArrayList<>();
120→
121→        // 員工年度假別額度檔ID查詢
122→        if (criteria.containsKey("empVacationId") && criteria.get("empVacationId") != null) {
123→            Object value = criteria.get("empVacationId");
124→            Integer empVacationId = parseInteger(value);
125→            if (empVacationId != null) {
126→                query.append(" AND l.empVacationId = ?").append(params.size() + 1);
127→                params.add(empVacationId);
128→            }
129→        }
130→
131→        // 代理員工ID查詢
132→        if (criteria.containsKey("empAgentId") && criteria.get("empAgentId") != null) {
133→            Object value = criteria.get("empAgentId");
134→            Integer empAgentId = parseInteger(value);
135→            if (empAgentId != null) {
136→                query.append(" AND l.empAgentId = ?").append(params.size() + 1);
137→                params.add(empAgentId);
138→            }
139→        }
140→
141→        // 簽核狀態查詢
142→        if (criteria.containsKey("leaveStatus") && criteria.get("leaveStatus") != null) {
143→            String leaveStatus = criteria.get("leaveStatus").toString().trim();
144→            if (!leaveStatus.isEmpty()) {
145→                query.append(" AND l.leaveStatus = ?").append(params.size() + 1);
146→                params.add(leaveStatus);
147→            }
148→        }
149→
150→        // 起始時間區間查詢
151→        if (criteria.containsKey("beginTimeFrom") && criteria.get("beginTimeFrom") != null) {
152→            Object value = criteria.get("beginTimeFrom");
153→            if (value instanceof LocalDateTime) {
154→                query.append(" AND l.beginTime >= ?").append(params.size() + 1);
155→                params.add(value);
156→            }
157→        }
158→
159→        if (criteria.containsKey("beginTimeTo") && criteria.get("beginTimeTo") != null) {
160→            Object value = criteria.get("beginTimeTo");
161→            if (value instanceof LocalDateTime) {
162→                query.append(" AND l.beginTime <= ?").append(params.size() + 1);
163→                params.add(value);
164→            }
165→        }
166→
167→        // 動態排序
168→        String sortBy = criteria.get("sortBy") != null ? criteria.get("sortBy").toString().trim() : null;
169→        String sortOrder = criteria.get("sortOrder") != null ? criteria.get("sortOrder").toString().trim() : "desc";
170→
171→        // 欄位映射：前端欄位名稱 -> Entity 欄位
172→        String orderByColumn = "l.beginTime"; // 預設排序欄位
173→        if (sortBy != null && !sortBy.isEmpty()) {
174→            orderByColumn = switch (sortBy) {
175→                case "empLeaveId" -> "l.empLeaveId";
176→                case "empVacationId" -> "l.empVacationId";
177→                case "empAgentId" -> "l.empAgentId";
178→                case "beginTime" -> "l.beginTime";
179→                case "endTime" -> "l.endTime";
180→                case "leaveStatus" -> "l.leaveStatus";
181→                case "createDt" -> "l.createDt";
182→                default -> "l.beginTime";
183→            };
184→        }
185→
186→        // 排序方向（只允許 ASC 或 DESC，防止注入）
187→        String orderDirection = "asc".equalsIgnoreCase(sortOrder) ? "ASC" : "DESC";
188→        query.append(" ORDER BY ").append(orderByColumn).append(" ").append(orderDirection);
189→
190→        PanacheQuery<TmEmpLeaveEntity> panacheQuery = find(query.toString(), params.toArray());
191→        return panacheQuery.list();
192→    }
193→
