258→    /**
259→     * 檢查是否存在重疊的請假區間
260→     * <p>
261→     * 用於新增/修改時檢查是否有衝突的請假單
262→     *
263→     * @param empVacationId 員工年度假別額度檔ID
264→     * @param beginTime     起始時間
265→     * @param endTime       結束時間
266→     * @param excludeId     要排除的請假單ID（修改時排除自己）
267→     * @return 是否有重疊
268→     */
269→    public static boolean hasOverlappingLeave(Integer empVacationId, LocalDateTime beginTime,
270→                                               LocalDateTime endTime, Integer excludeId) {
271→        String query = "empVacationId = ?1 AND leaveStatus != ?2 " +
272→                "AND ((beginTime <= ?3 AND endTime >= ?3) OR (beginTime <= ?4 AND endTime >= ?4) " +
273→                "OR (beginTime >= ?3 AND endTime <= ?4))";
274→        List<Object> params = new ArrayList<>();
275→        params.add(empVacationId);
