313→    private static Integer parseInteger(Object value) {
314→        if (value instanceof Number) {
315→            return ((Number) value).intValue();
316→        } else if (value instanceof String) {
317→            String strValue = ((String) value).trim();
318→            if (!strValue.isEmpty()) {
