package org.soetek.eap.tm;

import io.quarkus.test.junit.QuarkusTest;
import io.restassured.http.ContentType;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Order;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.TestMethodOrder;
import org.junit.jupiter.api.MethodOrderer;

import java.util.List;
import java.util.Map;

import static io.restassured.RestAssured.given;
import static org.hamcrest.Matchers.*;

/**
 * TM002 員工年度假別額度維護 — 整合測試
 * <p>
 * 測試策略：
 * - 全部從統一規格 unified-spec.md 推導，不從實作代碼推導
 * - 使用 @QuarkusTest + REST Assured 打真實 DB（MSSQL EAP_TEST）
 * - 種子資料由 import.sql 在 drop-and-create 後自動載入
 * <p>
 * 認證假設：
 * - 測試 profile 中需將 TM002 相關路由加入 public.paths 以繞過 JWT+Session 驗證
 * - 若無法繞過，需產生有效 JWT token 並在 Redis 建立 session
 * - 目前測試先以 anonymous 模式呼叫，若認證阻擋則需調整 test application.properties
 * <p>
 * 種子資料摘要（import.sql）：
 * - 部門：資訊部(orgId=1)、人事部(orgId=2)、業務部(orgId=3)
 * - 在職員工：EMP001(empId=1,資訊部)、EMP002(empId=2,資訊部)、EMP003(empId=3,人事部)
 * - 已離職員工：EMP004(empId=4,資訊部,leaveDate=2025-12-31)
 * - 假別：病假(V001)、事假(V002)、婚假(V003)
 * - 假別細項：普通病假(vacSubId=1)、住院病假(vacSubId=2,已失效)、事假(vacSubId=3)、婚假(vacSubId=4)
 * - 員工額度：EMP001有2筆2026年(病假+事假結算)、EMP002有1筆、EMP003有1筆、EMP001有1筆2025年、EMP004有1筆(離職)
 *
 * @author Test Agent (Phase 1)
 * @since 2026-03-26
 */
@QuarkusTest
@DisplayName("TM002 員工年度假別額度維護")
public class Tm002EmpVacationIntegrationTest {

    // ===================================================================
    // 常數定義
    // ===================================================================

    /**
     * 認證相關常數
     * 假設(A1)：測試 profile 中已將相關路由加入 public.paths
     * 若認證無法繞過，請替換為有效的 JWT token
     */
    private static final String TEST_TOKEN = "Bearer test-token";
    private static final String TEST_USER = "testUser";
    private static final String TEST_SESSION_ID = "test-session-id";

    // ===================================================================
    // BE-01：清單查詢 API（empVacationQuery）
    // 規格 §3.1：清單查詢與管理
    // ===================================================================

    @Nested
    @DisplayName("BE-01：清單查詢 API（empVacationQuery）")
    @TestMethodOrder(MethodOrderer.OrderAnnotation.class)
    class EmpVacationQueryTest {

        private static final String ROUTE = "empVacationQuery";

        /**
         * 規格 §3.1：無條件查詢應回傳所有在職員工的額度記錄
         * 種子資料中有 5 筆在職員工的額度（EMP001=2筆2026+1筆2025, EMP002=1筆, EMP003=1筆）
         * 已離職的 EMP004 不應出現
         */
        @Test
        @Order(1)
        @DisplayName("無條件查詢 — 應回傳所有在職員工的額度記錄")
        void testQueryWithoutFilters_shouldReturnAllRecords() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "page", 1,
                    "perPage", 50
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true))
                .body("data.records", notNullValue())
                .body("data.records.size()", greaterThanOrEqualTo(5))
                // 驗證已離職員工（EMP004）不在結果中
                .body("data.records.findAll { it.empNo == 'EMP004' }", hasSize(0));
        }

        /**
         * 規格 §3.1：年度篩選
         * 查詢 2026 年度 → 應只回傳 BEGIN_DATE 年份為 2026 的記錄
         * 種子資料中 2026 年度有 4 筆在職員工的額度
         */
        @Test
        @Order(2)
        @DisplayName("年度篩選 — 應只回傳指定年度的記錄")
        void testQueryByYear_shouldFilterByYear() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "effectiveDate", "2026",
                    "page", 1,
                    "perPage", 50
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true))
                .body("data.records", notNullValue())
                // 2026 年度在職員工額度：EMP001(病假+事假)、EMP002(病假)、EMP003(病假) = 4 筆
                .body("data.records.size()", is(4))
                // 2025 年度的記錄不應出現
                .body("data.records.findAll { it.year == 2025 }", hasSize(0));
        }

        /**
         * 規格 §3.1：部門篩選
         * 查詢資訊部（orgId=1）→ 應只回傳資訊部員工的記錄
         */
        @Test
        @Order(3)
        @DisplayName("部門篩選 — 應只回傳指定部門的記錄")
        void testQueryByDeptCode_shouldFilterByDepartment() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "deptCode", 1,
                    "page", 1,
                    "perPage", 50
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true))
                .body("data.records", notNullValue())
                // 資訊部員工：EMP001、EMP002（在職），EMP004（離職，不應出現）
                .body("data.records.findAll { it.deptCode == 1 }.size()", greaterThan(0))
                // 人事部員工不應出現
                .body("data.records.findAll { it.deptCode == 2 }", hasSize(0));
        }

        /**
         * 規格 §3.1：員工編號模糊篩選
         * 查詢 "EMP00" → 應回傳匹配的記錄
         */
        @Test
        @Order(4)
        @DisplayName("員工編號篩選 — 應支援模糊查詢")
        void testQueryByEmpNo_shouldFilterByEmployeeNo() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "empNo", "EMP001",
                    "page", 1,
                    "perPage", 50
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true))
                .body("data.records", notNullValue())
                // EMP001 有 3 筆額度（2026病假 + 2026事假 + 2025病假）
                .body("data.records.size()", greaterThanOrEqualTo(1))
                .body("data.records.every { it.empNo.contains('EMP001') }", is(true));
        }

        /**
         * 規格 §3.1：員工姓名模糊篩選
         * 查詢 "小明" → 應回傳張小明的記錄
         */
        @Test
        @Order(5)
        @DisplayName("員工姓名篩選 — 應支援模糊查詢")
        void testQueryByEmpName_shouldFilterByEmployeeName() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "empName", "小明",
                    "page", 1,
                    "perPage", 50
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true))
                .body("data.records", notNullValue())
                .body("data.records.size()", greaterThanOrEqualTo(1))
                .body("data.records[0].empNameCh", containsString("小明"));
        }

        /**
         * 規格 §3.1：分頁功能
         * 每頁 2 筆 → 驗證 totalCount 和 currentPage 正確
         */
        @Test
        @Order(6)
        @DisplayName("分頁功能 — 應回傳正確的分頁資訊")
        void testQueryWithPagination_shouldReturnPagedResults() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "page", 1,
                    "perPage", 2
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true))
                .body("data.records", notNullValue())
                .body("data.records.size()", lessThanOrEqualTo(2))
                .body("data.totalCount", greaterThan(2))
                .body("data.currentPage", is(1));
        }

        /**
         * 規格 §3.1：排序功能
         * 按員工編號降冪排序
         */
        @Test
        @Order(7)
        @DisplayName("排序功能 — 應支援欄位升冪/降冪排序")
        void testQueryWithSorting_shouldReturnSortedResults() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "sortBy", "empNo",
                    "sortOrder", "desc",
                    "page", 1,
                    "perPage", 50
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true))
                .body("data.records", notNullValue())
                .body("data.records.size()", greaterThan(0));
            // 注意：Groovy GPath 無法直接驗證排序順序，
            // 完整排序驗證需在 Service 單元測試中進行
        }

        /**
         * 規格 §3.1：已離職員工不應出現在查詢結果中
         * EMP004 已離職（LEAVE_DATE=2025-12-31）→ 不應出現
         */
        @Test
        @Order(8)
        @DisplayName("在職篩選 — 已離職員工不應出現在查詢結果中")
        void testQueryShouldOnlyReturnActiveEmployees() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "page", 1,
                    "perPage", 100
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true))
                .body("data.records", notNullValue())
                // 驗證已離職員工 EMP004 不在結果中
                .body("data.records.findAll { it.empNo == 'EMP004' }", hasSize(0));
        }

        /**
         * 規格 §3.1 清單欄位：
         * 年度、員工編號、姓名、假別名稱、生效日、失效日、可請額度、已用額度、剩餘額度
         */
        @Test
        @Order(9)
        @DisplayName("回傳欄位 — 應包含規格要求的所有清單欄位")
        void testQueryResponseFields_shouldContainAllRequiredFields() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "empNo", "EMP001",
                    "effectiveDate", "2026",
                    "page", 1,
                    "perPage", 50
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true))
                .body("data.records", notNullValue())
                .body("data.records.size()", greaterThan(0))
                // 驗證必要欄位存在
                .body("data.records[0].year", notNullValue())
                .body("data.records[0].empNo", notNullValue())
                .body("data.records[0].empNameCh", notNullValue())
                .body("data.records[0].vacationName", notNullValue())
                .body("data.records[0].effectiveStartDate", notNullValue())
                .body("data.records[0].effectiveEndDate", notNullValue())
                .body("data.records[0].totalHours", notNullValue())
                .body("data.records[0].usedHours", notNullValue())
                .body("data.records[0].remainingHours", notNullValue());
        }
    }

    // ===================================================================
    // BE-02：員工資訊查詢 API（tmEmpInfoQuery）
    // 規格 §3.2 步驟1：輸入年度+員工編號查詢
    // ===================================================================

    @Nested
    @DisplayName("BE-02：員工資訊查詢 API（tmEmpInfoQuery）")
    @TestMethodOrder(MethodOrderer.OrderAnnotation.class)
    class EmpInfoQueryTest {

        private static final String ROUTE = "tmEmpInfoQuery";

        /**
         * 規格 §3.2 步驟1：輸入有效員編 → 回傳員工資訊
         */
        @Test
        @Order(1)
        @DisplayName("查詢存在的員工 — 應回傳員工基本資訊")
        void testQueryExistingEmployee_shouldReturnEmpInfo() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "empAccount", "EMP001"
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true))
                .body("data", notNullValue())
                .body("data.empName", is("張小明"));
        }

        /**
         * 規格 §3.2 步驟1：查無此員工 → 提示錯誤
         */
        @Test
        @Order(2)
        @DisplayName("查詢不存在的員工 — 應回傳錯誤訊息")
        void testQueryNonExistingEmployee_shouldReturnError() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "empAccount", "NONEXIST999"
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                // 預期回傳錯誤（400 或 404 或 success=false）
                .body("success", is(false));
        }

        /**
         * 規格 §3.2 步驟1：未輸入員編 → 提示錯誤
         */
        @Test
        @Order(3)
        @DisplayName("未輸入員工編號 — 應回傳錯誤訊息")
        void testQueryWithoutEmpAccount_shouldReturnError() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of())
            .when()
                .post("/api/" + ROUTE)
            .then()
                // 預期回傳錯誤（empAccount 為必填）
                .body("success", is(false));
        }
    }

