        @Test
        @Order(4)
        @DisplayName("批次混合驗證 — 應回傳每位員工的驗證結果")
        void testValidateMultipleEmployees_shouldReturnMixedResults() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "empAccounts", List.of("EMP001", "EMP004", "NONEXIST")
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true))
                .body("data.results", notNullValue())
                .body("data.results.size()", is(3))
                // EMP001 有效
                .body("data.results.find { it.empAccount == 'EMP001' }.valid", is(true))
                // EMP004 已離職
                .body("data.results.find { it.empAccount == 'EMP004' }.valid", is(false))
                // NONEXIST 查無
                .body("data.results.find { it.empAccount == 'NONEXIST' }.valid", is(false));
        }
    }

    // ===================================================================
    // BE-08：批次匯入 — 批次建立 API（tm002BatchImport）
    // 規格 §3.4 步驟6：批次建立 TM_EMP_VACATION
    // ===================================================================

    @Nested
    @DisplayName("BE-08：批次匯入 — 批次建立 API（tm002BatchImport）")
    @TestMethodOrder(MethodOrderer.OrderAnnotation.class)
    class BatchImportTest {

        /**
         * 預期路由名稱（假設 A4）
         */
        private static final String ROUTE = "tm002BatchImport";

        /**
         * 規格 §3.4 步驟6：對有效員工批次建立 TM_EMP_VACATION
         */
        @Test
        @Order(1)
        @DisplayName("批次匯入 — 應為有效員工建立假別額度記錄")
        void testBatchImport_shouldCreateRecordsForValidEmployees() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "empIds", List.of(1, 2, 3),
                    "vacationSubId", 4,               // 婚假細項
                    "maxHours", 64.0,
                    "beginDate", "2026-01-01",
                    "endDate", "2026-12-31"
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true))
                .body("data.createdCount", is(3));
        }

        /**
         * 規格 §3.4 批次套用條件：必填欄位檢查
         * 假別/細項/可請時數/起始日/結束日均為必填
         */
        @Test
        @Order(2)
        @DisplayName("批次匯入缺少必填欄位 — 應回傳錯誤")
        void testBatchImport_shouldValidateRequiredFields() {
            // 缺少 vacationSubId
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "empIds", List.of(1, 2),
                    // 缺少 vacationSubId
                    "maxHours", 64.0,
                    "beginDate", "2026-01-01",
                    "endDate", "2026-12-31"
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .body("success", is(false));
        }

        /**
         * 規格 §3.4 批次套用條件 + 業務規則 B11：
         * 結束日不可早於起始日 → 錯誤
         */
        @Test
        @Order(3)
        @DisplayName("結束日早於起始日 — 應回傳錯誤（B11）")
        void testBatchImport_endDateBeforeBeginDate_shouldReturnError() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "empIds", List.of(1),
                    "vacationSubId", 1,
                    "maxHours", 240.0,
                    "beginDate", "2026-12-31",         // 起始日較晚
                    "endDate", "2026-01-01"            // 結束日較早 → 違反 B11
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .body("success", is(false));
        }

        /**
         * 規格 §3.4 + 業務規則 B1：
         * 批次建立時 UNUSED_HOURS = MAX_HOURS - 0（新建，已用為 0）
         */
        @Test
        @Order(4)
        @DisplayName("批次建立應自動計算剩餘時數 — UNUSED = MAX - 0（B1）")
        void testBatchImport_shouldCalculateUnusedHours() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "empIds", List.of(3),
                    "vacationSubId", 3,               // 事假細項
                    "maxHours", 112.0,
                    "beginDate", "2026-01-01",
                    "endDate", "2026-12-31"
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .statusCode(200)
                .body("success", is(true));
            // UNUSED_HOURS 應為 112.0（MAX_HOURS - 0）
            // 可透過後續查詢 API 驗證
        }

        /**
         * 無效假別細項 → 錯誤
         */
        @Test
        @Order(5)
        @DisplayName("無效假別細項 — 應回傳錯誤")
        void testBatchImport_withInvalidVacationSubId_shouldReturnError() {
            given()
                .contentType(ContentType.JSON)
                .header("Authorization", TEST_TOKEN)
                .header("X-User", TEST_USER)
                .header("X-Session-Id", TEST_SESSION_ID)
                .body(Map.of(
                    "empIds", List.of(1),
                    "vacationSubId", 99999,            // 不存在的假別細項
                    "maxHours", 240.0,
                    "beginDate", "2026-01-01",
                    "endDate", "2026-12-31"
                ))
            .when()
                .post("/api/" + ROUTE)
            .then()
                .body("success", is(false));
        }
    }
}

